void reverse_in_place(std::vector<double>& v){
    size_t i = 0;
    size_t j = v.size() - 1;
    while (i < j){
        double tmp = v[i];
        v[i] = v[j];
        v[j] = tmp;
        ++i; --j;
    }
}

